(function () {
  'use strict';

  function back2top() {
    var $window = $(window);
    var $btn = $('#back-to-top');

    $window.on('scroll', function () {
      $window.scrollTop() > 50 ? $btn.fadeIn() : $btn.fadeOut();
    });

    $btn.on('click', function () {
      $window.scrollTop(0);
    });
  }

  function loadTooptip() {
    var tooltipTriggerList = document.querySelectorAll('[data-bs-toggle="tooltip"]');
    Array.prototype.slice.call(tooltipTriggerList).map(function (tooltipTriggerEl) {
      return new bootstrap.Tooltip(tooltipTriggerEl);
    });
  }

  function modeWatcher() {
    var $toggleElem = $('.mode-toggle');

    if ($toggleElem.length === 0) {
      return;
    }

    $toggleElem.off().on('click', function (e) {
      var $target = $(e.target);
      var $btn = $target.prop('tagName') === 'BUTTON' ? $target : $target.parent();

      modeToggle.flipMode();
      $btn.trigger('blur');
    });
  }

  function sidebarExpand() {
    var $body = $('body');
    var isExpanded = false;

    function toggle() {
      isExpanded === false ? $body.attr('sidebar-display', '') : $body.removeAttr('sidebar-display');
      isExpanded = !isExpanded;
    }

    $('#sidebar-trigger').on('click', toggle);
    $('#mask').on('click', toggle);
  }

  function categoryCollapse() {
    $('.collapse').on('hide.bs.collapse', function () {
      var parentId = 'h_' + $(this).attr('id').substring('l_'.length);
      if (parentId) {
        $('#' + parentId + ' .far.fa-folder-open').attr('class', 'far fa-folder fa-fw');
        $('#' + parentId + ' i.fas').addClass('rotate');
        $('#' + parentId).removeClass('hide-border-bottom');
      }
    });

    $('.collapse').on('show.bs.collapse', function () {
      var parentId = 'h_' + $(this).attr('id').substring('l_'.length);
      if (parentId) {
        $('#' + parentId + ' .far.fa-folder').attr('class', 'far fa-folder-open fa-fw');
        $('#' + parentId + ' i.fas').removeClass('rotate');
        $('#' + parentId).addClass('hide-border-bottom');
      }
    });
  }

  back2top();
  loadTooptip();
  modeWatcher();
  sidebarExpand();
  categoryCollapse();
})();
